// // Asynchronous reset and load capabilities
// Output is set to HIGH on rising edge of clock when reset is active
// Output is updated to data input on rising edge of clock when load is active
// Otherwise, output retains its previous value
module top_module(rst, clk, ld, d, q);input rst, clk, ld, d; 
	output q;
	reg temp;

	always @ (posedge clk)
		if (rst) 
			temp = 1'b0;
		else if (ld)
    		temp = d;

	assign q = temp;
endmodule

